#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define ALPHABET_SIZE 26

typedef struct TrieNode {
    struct TrieNode* children[ALPHABET_SIZE];
    int isEnd;
} TrieNode;

TrieNode* createNode() {
    TrieNode* node = (TrieNode*)malloc(sizeof(TrieNode));
    for (int i = 0; i < ALPHABET_SIZE; i++) {
        node->children[i] = NULL;
    }
    node->isEnd = 0;
    return node;
}

typedef struct Trie {
    TrieNode* root;
} Trie;

Trie* createTrie() {
    Trie* trie = (Trie*)malloc(sizeof(Trie));
    trie->root = createNode();
    return trie;
}

void insert(Trie* trie, const char* word) {
    TrieNode* node = trie->root;
    for (int i = 0; word[i]; i++) {
        int index = word[i] - 'a';
        if (!node->children[index]) {
            node->children[index] = createNode();
        }
        node = node->children[index];
    }
    node->isEnd = 1;
}

int search(Trie* trie, const char* word) {
    TrieNode* node = trie->root;
    for (int i = 0; word[i]; i++) {
        int index = word[i] - 'a';
        if (!node->children[index]) {
            return 0;
        }
        node = node->children[index];
    }
    return node->isEnd;
}

int startsWith(Trie* trie, const char* prefix) {
    TrieNode* node = trie->root;
    for (int i = 0; prefix[i]; i++) {
        int index = prefix[i] - 'a';
        if (!node->children[index]) {
            return 0;
        }
        node = node->children[index];
    }
    return 1;
}

void freeTrieNode(TrieNode* node) {
    if (!node) return;
    for (int i = 0; i < ALPHABET_SIZE; i++) {
        freeTrieNode(node->children[i]);
    }
    free(node);
}

void freeTrie(Trie* trie) {
    freeTrieNode(trie->root);
    free(trie);
}

int main() {
    Trie* trie = createTrie();
    const char* words[] = {"cat", "car", "cart"};
    for (int i = 0; i < 3; i++) {
        insert(trie, words[i]);
    }
    printf("Search \"car\": %d\n", search(trie, "car"));
    printf("Search \"dog\": %d\n", search(trie, "dog"));
    printf("Starts with \"ca\": %d\n", startsWith(trie, "ca"));
    freeTrie(trie);
    return 0;
}
// Output: Search "car": 1
// Output: Search "dog": 0
// Output: Starts with "ca": 1

