#include <iostream>
#include <unordered_map>

class TrieNode {
public:
    std::unordered_map<char, TrieNode*> children;
    bool isEnd;
    TrieNode() : isEnd(false) {}
};

class Trie {
private:
    TrieNode* root;

public:
    Trie() {
        root = new TrieNode();
    }

    void insert(const std::string& word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                node->children[c] = new TrieNode();
            }
            node = node->children[c];
        }
        node->isEnd = true;
    }

    bool search(const std::string& word) {
        TrieNode* node = root;
        for (char c : word) {
            if (node->children.find(c) == node->children.end()) {
                return false;
            }
            node = node->children[c];
        }
        return node->isEnd;
    }

    bool startsWith(const std::string& prefix) {
        TrieNode* node = root;
        for (char c : prefix) {
            if (node->children.find(c) == node->children.end()) {
                return false;
            }
            node = node->children[c];
        }
        return true;
    }

    ~Trie() {
        deleteTrieNode(root);
    }

private:
    void deleteTrieNode(TrieNode* node) {
        if (!node) return;
        for (auto& pair : node->children) {
            deleteTrieNode(pair.second);
        }
        delete node;
    }
};

int main() {
    Trie trie;
    std::string words[] = {"cat", "car", "cart"};
    for (const auto& word : words) {
        trie.insert(word);
    }
    std::cout << "Search \"car\": " << (trie.search("car") ? "true" : "false") << "\n";
    std::cout << "Search \"dog\": " << (trie.search("dog") ? "true" : "false") << "\n";
    std::cout << "Starts with \"ca\": " << (trie.startsWith("ca") ? "true" : "false") << "\n";
    return 0;
}
// Output: Search "car": true
// Output: Search "dog": false
// Output: Starts with "ca": true

